88	__device__ DWORDX4 read_dwordx4(BufferResource& buffer, int soffset, int nstride) {
89	    DWORDX4 data;
90	    //volatile int dummy[40] = {0};
91	    int lane_offset = threadIdx.x * sizeof(DWORDX4);
92	    int soff = soffset;
93	    auto r = amd_wave_read_first_lane(buffer.descriptor);
94	    asm volatile("buffer_load_dwordx4 %[vdst], %[vaddr], %[srsrc], %[soffset] offen\n"
95	        :[vdst]"=v"(data)
96	        :[vaddr]"v"(lane_offset), [srsrc]"s"(r), [soffset]"s"(soff));
97	    return data;
98	}
