100	template<typename T>
101	__device__ T buffer_load_dwordx4(BufferResource& buffer, int soffset, int voffset, bool is_asm=false) {
102	    T v;
103	    if (is_asm) {
104	        auto r = amd_wave_read_first_lane(buffer.descriptor);
105	        asm volatile("buffer_load_dwordx4 %[vdst], %[vaddr], %[srsrc], %[soffset] offen\n"
106	            :[vdst]"=v"(v)
107	            :[vaddr]"v"(voffset), [srsrc]"s"(r), [soffset]"s"(soffset));
108	    } else {
109	        v = *(T*)((char*)buffer.address + soffset + voffset);
110	    }
111	    return v;
