130	__device__ T buffer_load_dword(BufferResource& buffer, int soffset, int voffset, int coffset, bool is_asm=false) {
131	    T v;
132	    if (is_asm) {
133	        int32x4_t r = __builtin_bit_cast(int32x4_t, buffer);
134	        r.x         = __builtin_amdgcn_readfirstlane(r.x);
135	        r.y         = __builtin_amdgcn_readfirstlane(r.y);
136	        r.z         = __builtin_amdgcn_readfirstlane(r.z);
137	        r.w         = __builtin_amdgcn_readfirstlane(r.w);
138	
139	        //auto r = amd_wave_read_first_lane(buffer.descriptor);
140	        asm volatile("buffer_load_dword %[vdst], %[vaddr], %[srsrc], 0 offen offset:%[coffset]\n"
141	            :[vdst]"=v"(v)
142	            :[vaddr]"v"(voffset), [srsrc]"s"(r), [coffset]"n"(coffset)
143	            : "memory");
144	    } else {
145	        int32x4_t r = __builtin_bit_cast(int32x4_t, buffer);
146	        auto d = llvm_amdgcn_raw_buffer_load_fp32(r, voffset + coffset, soffset, 0);
147	        v = __builtin_bit_cast(T, d);
148	        //v = *(T*)((char*)buffer.address + soffset + voffset + coffset);
149	    }
150	    return v;
151	}
