212	struct share_buf_t {
213	    __bf16* buf;
214	    __device__ share_buf_t(__bf16* buf) : buf(buf) {}
215	      // for output reduce: 4 warpx16xS
216	    __device__ __bf16* get_out_buf(uint warp_id) {
217	        return buf + 16 * S * warp_id;
218	    }
219	    // for key cache: 4 warpx16xS
220	    __device__ __bf16* get_key_buf(uint warp_id) {
221	        return buf + 16 * S * warp_id;
222	    }
223	    // for value cache: 4 warpx16xS
224	    __device__ __bf16* get_value_buf(uint warp_id) {
225	        return buf + 16 * S * warp_id;
226	    }
227	    // 4warp * (16m + 1)
228	    __device__ float* get_max_buf(uint m, uint warp_id) {
229	        return (float*)buf + m + warp_id * 16;
230	    }
231	    __device__ float* get_sum_buf(uint m, uint warp_id) {
232	        return (float*)buf + m + warp_id * 16 + 64;
233	    }
234	    __device__ uint* get_idx_buf(uint warp_id) {
235	        return (uint*)get_key_buf(warp_id);
236	    }
237	};
